```java
import java.util.*;

public class Solution {
    public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
        Map<String, Integer> businessPriority = new HashMap<>();
        businessPriority.put("electronics", 0);
        businessPriority.put("grocery", 1);
        businessPriority.put("pharmacy", 2);
        businessPriority.put("restaurant", 3);

        List<Coupon> validCoupons = new ArrayList<>();

        for (int i = 0; i < code.length; i++) {
            String c = code[i];
            String bl = businessLine[i];
            boolean active = isActive[i];

            if (c.isEmpty()) continue;

            if (!c.matches("^\\w+$")) continue;

            if (!businessPriority.containsKey(bl)) continue;

            if (!active) continue;

            validCoupons.add(new Coupon(c, bl));
        }

        validCoupons.sort((a, b) -> {
            int priorityA = businessPriority.get(a.businessLine);
            int priorityB = businessPriority.get(b.businessLine);
            if (priorityA != priorityB) {
                return priorityA - priorityB;
            }
            return a.code.compareTo(b.code);
        });

        String[] result = new String[validCoupons.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = validCoupons.get(i).code;
        }

        return result;
    }

    static class Coupon {
        String code;
        String businessLine;

        public Coupon(String code, String businessLine) {
            this.code = code;
            this.businessLine = businessLine;
        }
    }
}
