```java
import java.util.ArrayList;
import java.util.Arrays;
import java.util.List;

public class Solution {
    public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
        List<String[]> validCoupons = new ArrayList<>();

        for (int i = 0; i < code.length; i++) {
            String c = code[i];
            String bl = businessLine[i];
            boolean active = isActive[i];

            if (c.isEmpty()) {
                continue;
            }

            if (!c.matches("^[a-zA-Z0-9_]+$")) {
                continue;
            }

            if (!bl.equals("electronics") && !bl.equals("grocery") && !bl.equals("pharmacy") && !bl.equals("restaurant")) {
                continue;
            }

            if (!active) {
                continue;
            }

            validCoupons.add(new String[]{c, bl});
        }

        validCoupons.sort((a, b) -> {
            int priorityA = getPriority(a[1]);
            int priorityB = getPriority(b[1]);
            if (priorityA != priorityB) {
                return priorityA - priorityB;
            }
            return a[0].compareTo(b[0]);
        });

        String[] result = new String[validCoupons.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = validCoupons.get(i)[0];
        }

        return result;
    }

    private static int getPriority(String businessLine) {
        switch (businessLine) {
            case "electronics": return 0;
            case "grocery": return 1;
            case "pharmacy": return 2;
            case "restaurant": return 3;
            default: return -1;
        }
    }
}
```

