import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

public class Solution {
    public static String[] solve(String[] code, String[] businessLine, boolean[] isActive) {
        Map<String, Integer> businessPriority = new HashMap<>();
        businessPriority.put("electronics", 0);
        businessPriority.put("grocery", 1);
        businessPriority.put("pharmacy", 2);
        businessPriority.put("restaurant", 3);

        List<String[]> validCoupons = new ArrayList<>();

        for (int i = 0; i < code.length; i++) {
            String c = code[i];
            String bl = businessLine[i];
            boolean active = isActive[i];

            if (c.length() > 0 && c.matches("^[\\w]+$") && businessPriority.containsKey(bl) && active) {
                validCoupons.add(new String[]{c, bl});
            }
        }

        validCoupons.sort((a, b) -> {
            int priorityA = businessPriority.get(a[1]);
            int priorityB = businessPriority.get(b[1]);
            if (priorityA != priorityB) {
                return priorityA - priorityB;
            }
            return a[0].compareTo(b[0]);
        });

        String[] result = new String[validCoupons.size()];
        for (int i = 0; i < result.length; i++) {
            result[i] = validCoupons.get(i)[0];
        }
        return result;
    }
}
